const makeId = (industry: string, title: string) =>
  `${industry}-${title.toLowerCase().replace(/[^a-z0-9]+/g, "-")}`;

const o = (industryId: string, title: string, subcategory: string, level: "entry" | "mid" | "senior" | "lead" | "executive", description: string, coreSkills: string[], secondarySkills: string[], tools: string[], educationPaths: string[], portfolioExpectations: string[], resumeKeywords: string[], demandLevel: "very-high" | "high" | "moderate" | "emerging" | "niche", salaryMin: number, salaryMax: number, careerProgression: string[], opts?: { isFutureReady?: boolean; isHybrid?: boolean; hybridDomains?: string[] }): Occupation => {
  const INR_MULTIPLIERS: Record<string, { min: number; max: number }> = {
    entry:     { min: 0.08, max: 0.12 },
    mid:       { min: 0.18, max: 0.28 },
    senior:    { min: 0.30, max: 0.45 },
    lead:      { min: 0.40, max: 0.60 },
    executive: { min: 0.55, max: 0.80 },
  };
  const multiplier = INR_MULTIPLIERS[level] ?? INR_MULTIPLIERS['mid'];
  const inrMin = Math.round((salaryMin * multiplier.min) / 100000) * 100000;
  const inrMax = Math.round((salaryMax * multiplier.max) / 100000) * 100000;

  return {
    id: makeId(industryId, title), title, industryId, subcategory, level, description, coreSkills, secondarySkills, tools, educationPaths, portfolioExpectations, resumeKeywords, demandLevel, salaryBand: { min: inrMin, max: inrMax, currency: "INR" }, careerProgression, ...opts
  };
};

