// Calculate role counts per industry
industries.forEach((industry) => {
  industry.roleCount = allOccupations.filter((o) => o.industryId === industry.id).length;
});

export const occupations = allOccupations;

export function getOccupationsByIndustry(industryId: string): Occupation[] {
  return allOccupations.filter((o) => o.industryId === industryId);
}

export function getOccupationsBySubcategory(industryId: string, subcategory: string): Occupation[] {
  return allOccupations.filter((o) => o.industryId === industryId && o.subcategory === subcategory);
}

export function getOccupationById(id: string): Occupation | undefined {
  return allOccupations.find((o) => o.id === id);
}

export function searchOccupations(query: string): Occupation[] {
  const lower = query.toLowerCase();
  return allOccupations.filter(
    (o) =>
      o.title.toLowerCase().includes(lower) ||
      o.coreSkills.some((s) => s.toLowerCase().includes(lower)) ||
      o.secondarySkills.some((s) => s.toLowerCase().includes(lower)) ||
      o.tools.some((t) => t.toLowerCase().includes(lower)) ||
      o.resumeKeywords.some((k) => k.toLowerCase().includes(lower)) ||
      o.description.toLowerCase().includes(lower) ||
      o.subcategory.toLowerCase().includes(lower)
  );
}

export function getFutureReadyOccupations(): Occupation[] {
  return allOccupations.filter((o) => o.isFutureReady);
}

export function getHybridOccupations(): Occupation[] {
  return allOccupations.filter((o) => o.isHybrid);
}

export function getOccupationCount(): number {
  return allOccupations.length;
}
